// Interface usage in a service
@injectable()
export class OrderService {
  @inject(INVERSITY_TYPES.PersistenceContext)
  private _persistence: IPersistenceContext;

  async createOrder(data: OrderInput): Promise<Order> {
    // All operations inside inTransaction are atomic
    return await this._persistence.inTransaction(
      async (em: EntityManager) => {
        const order = em.create(Order, data);
        await em.save(order);

        // Update inventory (also in same transaction)
        await this.updateInventory(em, data.items);

        return order;
      }
    );
  }
}

@Controller('/api/v1/emails')
export class EmailController {
  @inject(INVERSITY_TYPES.QueueClient)
  private queueClient: IQueueClient;

  @Post('/send')
  async sendEmail(req: Request, res: Response) {
    const jobId = await this.queueClient.addJob(
      'email-queue',
      'send-welcome',
      { to: req.body.email, template: 'welcome' },
      { attempts: 3, backoff: { type: 'exponential', delay: 1000 } }
    );

    return res.status(202).json({ jobId, status: 'queued' });
  }
}

@QueueWorker('email-queue', { concurrency: 5 })
@injectable()
export class EmailWorker implements IQueueWorkerHandler {
  async process(job: Job<EmailData>): Promise<void> {
    await job.updateProgress(10);
    await this.sendEmail(job.data);
    await job.updateProgress(100);
  }

  onCompleted(job: Job): void {
    console.log(`Email sent successfully: ${job.id}`);
  }

  onFailed(job: Job, error: Error): void {
    console.error(`Email failed: ${error.message}`);
  }

  onProgress(job: Job, progress: number): void {
    console.log(`Job ${job.id} progress: ${progress}%`);
  }
}

